// this logic takes the raw text from access-filters.txt and parses it into the 
// format needed for the advanced review sections. 
// The text file is structured with section titles followed by lists of access 
// features, separated by blank lines
function parseFilterSection(sectionText) {
    const [rawTitle, ...items] = sectionText
        .split('\n')
        .map((line) => line.trim())
        .filter(Boolean)

    return {
        rawTitle,
        items,
    }
}

const parsedFilterSections = accessFiltersText
    .split(/\n\s*\n/)
    .map((section) => section.trim())
    .filter(Boolean)
    .map(parseFilterSection)

export const advancedReviewSections = parsedFilterSections.map(({ rawTitle, items }) => {
    const metadata = reviewSectionMetadata[rawTitle.toLowerCase()]

    return {
        id: metadata?.id ?? rawTitle.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, ''),
        title: metadata?.title ?? rawTitle,
        ratingPrompt: metadata?.ratingPrompt ?? `Rate your ${rawTitle.toLowerCase()} experience`,
        tags: items,
        summaryPrompt: metadata?.summaryPrompt ?? 'Share details about your experience in this area.',
    }
})